package com.google.gson.examples.android.model;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.lang.reflect.WildcardType;
import com.google.gson.annotations.SerializedName;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;

class CartTest {

  @Test
  void testGetLineItems_returnsLineItemsList() {
    List<LineItem> items = new ArrayList<>();
    items.add(new LineItem("item1", 2));
    items.add(new LineItem("item2", 5));
    Cart cart = new Cart(items, "buyerName", "1234-5678-9012-3456");

    List<LineItem> result = cart.getLineItems();

    assertNotNull(result);
    assertEquals(2, result.size());
    assertEquals("item1", result.get(0).getName());
    assertEquals(2, result.get(0).getQuantity());
    assertEquals("item2", result.get(1).getName());
    assertEquals(5, result.get(1).getQuantity());
  }

  // Minimal LineItem class for testing
  static class LineItem {
    private final String name;
    private final int quantity;

    LineItem(String name, int quantity) {
      this.name = name;
      this.quantity = quantity;
    }

    String getName() {
      return name;
    }

    int getQuantity() {
      return quantity;
    }
  }
}
